/**
 * @module payai/facilitator
 *
 * Small, focused package for configuring the PayAI facilitator — mirroring
 * the design of `@coinbase/x402`. Merchants add one import and get a
 * ready-made `FacilitatorConfig` with automatic JWT authentication.
 *
 * @example
 * ```typescript
 * import { facilitator } from "@payai/facilitator";
 * import { HTTPFacilitatorClient } from "@x402/core/server";
 *
 * const client = new HTTPFacilitatorClient(facilitator);
 * // Done. Set PAYAI_API_KEY_ID + PAYAI_API_KEY_SECRET env vars for auth.
 * ```
 */

import { createPayAIAuthHeaders } from "./payaiJwt";

/** Default PayAI facilitator URL. */
const PAYAI_FACILITATOR_URL = "https://facilitator.payai.network";

/**
 * Minimal facilitator client config shape used by `HTTPFacilitatorClient`.
 *
 * This intentionally mirrors `@x402/core/server`'s `FacilitatorConfig` *structurally*
 * without importing the type. That keeps `@payai/facilitator` usable in:
 * - v2 projects that already depend on `@x402/core` (recommended)
 * - v1 projects (x402-express/x402-next/x402-hono) that only want JWT header helpers
 * - custom clients (e.g. x402-solana) that don't otherwise install `@x402/core`
 */
export interface FacilitatorConfig {
  url?: string;
  /**
   * Custom auth header factory. Called before every facilitator request.
   * Return per-endpoint headers (e.g. `Authorization: Bearer <jwt>`).
   */
  createAuthHeaders?: () => Promise<{
    verify: Record<string, string>;
    settle: Record<string, string>;
    supported: Record<string, string>;
  }>;
}

/**
 * Create a `FacilitatorConfig` for the PayAI facilitator.
 *
 * When API key credentials are provided (or available as env vars),
 * all facilitator requests are automatically authenticated with a JWT
 * Bearer token. The JWT is cached and refreshed transparently.
 *
 * @param apiKeyId - PayAI API Key ID (falls back to `PAYAI_API_KEY_ID` env var)
 * @param apiKeySecret - PayAI API Key Secret (falls back to `PAYAI_API_KEY_SECRET` env var)
 * @returns A `FacilitatorConfig` ready for `HTTPFacilitatorClient`
 *
 * @example
 * ```typescript
 * // Explicit credentials
 * const config = createFacilitatorConfig("my-key-id", "payai_sk_...");
 * const client = new HTTPFacilitatorClient(config);
 *
 * // Or let it read from env vars
 * const config = createFacilitatorConfig();
 * ```
 */
export function createFacilitatorConfig(
  apiKeyId?: string,
  apiKeySecret?: string,
): FacilitatorConfig {
  // NOTE: We use direct `process.env.FOO` access to preserve bundler env inlining
  // (e.g. Next.js) where `process.env.*` is statically substituted at build time.
  const keyId = apiKeyId ?? process.env.PAYAI_API_KEY_ID;
  const keySecret = apiKeySecret ?? process.env.PAYAI_API_KEY_SECRET;

  const config: FacilitatorConfig = { url: PAYAI_FACILITATOR_URL };

  if (keyId && keySecret) {
    config.createAuthHeaders = createPayAIAuthHeaders(keyId, keySecret);
  }

  return config;
}

/**
 * Pre-built facilitator config that reads credentials from environment variables.
 *
 * Set `PAYAI_API_KEY_ID` and `PAYAI_API_KEY_SECRET` in your environment
 * to enable automatic JWT authentication. Without them, the config still
 * works (free tier, no auth).
 *
 * @example
 * ```typescript
 * import { facilitator } from "@payai/facilitator";
 * import { HTTPFacilitatorClient } from "@x402/core/server";
 *
 * const client = new HTTPFacilitatorClient(facilitator);
 * ```
 */
export const facilitator: FacilitatorConfig = {
  url: PAYAI_FACILITATOR_URL,
  /**
   * Read credentials from env at request-time.
   *
   * This avoids evaluating `process.env` during module initialization, which makes
   * the default export safe to import in non-Node runtimes (keys can still be passed
   * explicitly via `createFacilitatorConfig()`).
   *
   * @returns auth headers per facilitator endpoint, or empty objects for free tier
   */
  createAuthHeaders: async () => {
    const keyId = process.env.PAYAI_API_KEY_ID;
    const keySecret = process.env.PAYAI_API_KEY_SECRET;

    // No credentials configured → free tier (no auth)
    if (!keyId || !keySecret) {
      return { verify: {}, settle: {}, supported: {} };
    }

    return createPayAIAuthHeaders(keyId, keySecret)();
  },
};

// Re-export JWT utilities for advanced use cases
export { getOrGenerateJwt, createPayAIAuthHeaders, clearJwtCache } from "./payaiJwt";
export type { PayAIJwtOptions } from "./payaiJwt";
