/**
 * PayAI API Key JWT Authentication
 *
 * Provides Ed25519 (EdDSA) JWT generation for authenticating with the PayAI facilitator.
 * JWTs are used as Bearer tokens for credit-based access (bypassing free tier limits).
 *
 * Uses the Web Crypto API for zero-dependency, cross-runtime compatibility
 * (Node.js 18+, Edge runtimes, browsers).
 */

// =============================================================================
// Types
// =============================================================================

/**
 * Options for generating a PayAI API key JWT.
 */
export interface PayAIJwtOptions {
  /** API Key ID (used as `kid` in JWT header and `sub` in payload) */
  apiKeyId: string;
  /**
   * API Key Secret (Ed25519 private key in PKCS#8/DER format, base64-encoded).
   *
   * Accepted formats:
   * - Raw base64: `"<base64>"`
   * - PayAI-prefixed (as shown in merchant portal): `"payai_sk_<base64>"`
   */
  apiKeySecret: string;
  /** JWT expiration in seconds (default: 120) */
  expiresIn?: number;
  /** Issuer claim (default: "payai-merchant") */
  issuer?: string;
}

// =============================================================================
// Internal Helpers
// =============================================================================

/**
 * Base64URL encode a Uint8Array (JWT-safe encoding without padding).
 *
 * @param data - the binary data to encode
 * @returns base64url-encoded string
 */
function base64UrlEncode(data: Uint8Array): string {
  let binary = "";
  for (let i = 0; i < data.byteLength; i++) {
    binary += String.fromCharCode(data[i]);
  }
  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

/**
 * Base64URL encode a plain string.
 *
 * @param str - the string to encode
 * @returns base64url-encoded string
 */
function base64UrlEncodeString(str: string): string {
  return base64UrlEncode(new TextEncoder().encode(str));
}

/**
 * Decode a base64 (or base64url) string to Uint8Array.
 *
 * @param base64 - the base64 or base64url string to decode
 * @returns decoded bytes
 */
function base64ToUint8Array(base64: string): Uint8Array {
  const standardized = base64.replace(/-/g, "+").replace(/_/g, "/");
  const binary = atob(standardized);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

/**
 * Strip the `payai_sk_` prefix from a secret if present.
 *
 * The merchant portal returns secrets as `"payai_sk_<base64>"` to make them
 * visually identifiable as sensitive. The JWT signer needs raw base64.
 *
 * @param apiKeySecret - the raw or prefixed API key secret
 * @returns the base64-encoded secret without prefix
 */
function normalizeApiKeySecret(apiKeySecret: string): string {
  const trimmed = apiKeySecret.trim();
  return trimmed.startsWith("payai_sk_") ? trimmed.slice("payai_sk_".length) : trimmed;
}

/**
 * Generate a UUID v4 for JWT `jti` (replay protection).
 *
 * @returns a random UUID v4 string
 */
function generateUUID(): string {
  if (typeof crypto !== "undefined" && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, c => {
    const r = (Math.random() * 16) | 0;
    const v = c === "x" ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

// =============================================================================
// JWT Generation
// =============================================================================

/**
 * Generate a signed JWT for PayAI API key authentication.
 *
 * Uses Ed25519 (EdDSA) signing via the Web Crypto API, matching the
 * PayAI facilitator's verification algorithm.
 *
 * @param options - JWT generation options
 * @returns Signed JWT string
 * @throws Error if the key format is invalid or signing fails
 */
export async function generatePayAIApiKeyJwt(options: PayAIJwtOptions): Promise<string> {
  const { apiKeyId, apiKeySecret, expiresIn = 120, issuer = "payai-merchant" } = options;

  if (!apiKeyId || !apiKeySecret) {
    throw new Error("apiKeyId and apiKeySecret are required");
  }

  const now = Math.floor(Date.now() / 1000);

  const header = { alg: "EdDSA", typ: "JWT", kid: apiKeyId };
  const payload = {
    sub: apiKeyId,
    iss: issuer,
    iat: now,
    exp: now + expiresIn,
    jti: generateUUID(),
  };

  const headerB64 = base64UrlEncodeString(JSON.stringify(header));
  const payloadB64 = base64UrlEncodeString(JSON.stringify(payload));
  const message = `${headerB64}.${payloadB64}`;

  try {
    const keyBytes = base64ToUint8Array(normalizeApiKeySecret(apiKeySecret));

    const privateKey = await crypto.subtle.importKey(
      "pkcs8",
      keyBytes.buffer as ArrayBuffer,
      { name: "Ed25519" },
      false,
      ["sign"],
    );

    const signature = await crypto.subtle.sign(
      "Ed25519",
      privateKey,
      new TextEncoder().encode(message).buffer as ArrayBuffer,
    );

    return `${message}.${base64UrlEncode(new Uint8Array(signature))}`;
  } catch (error) {
    const msg = error instanceof Error ? error.message : "Unknown error";
    throw new Error(
      `Failed to sign JWT: ${msg}. ` +
        `Ensure apiKeySecret is a valid base64-encoded Ed25519 private key in PKCS#8 format.`,
    );
  }
}

// =============================================================================
// JWT Caching
// =============================================================================

interface CachedJwt {
  token: string;
  expiresAt: number;
}

/**
 * Per-key JWT cache. Keyed by `apiKeyId` so multiple API keys can coexist
 * in the same process without invalidating each other's tokens.
 */
const jwtCache = new Map<string, CachedJwt>();

/** Seconds before expiry to proactively regenerate the token. */
const REFRESH_BUFFER_SECONDS = 30;

/**
 * Get a cached JWT or generate a fresh one.
 *
 * Reuses the cached token until `REFRESH_BUFFER_SECONDS` before its expiry,
 * minimising signing operations while ensuring requests never use an expired token.
 *
 * @param options - JWT generation options
 * @returns JWT string (possibly from cache)
 */
export async function getOrGenerateJwt(options: PayAIJwtOptions): Promise<string> {
  const now = Math.floor(Date.now() / 1000);
  const cached = jwtCache.get(options.apiKeyId);

  if (cached && cached.expiresAt > now + REFRESH_BUFFER_SECONDS) {
    return cached.token;
  }

  const expiresIn = options.expiresIn ?? 120;
  const token = await generatePayAIApiKeyJwt(options);

  jwtCache.set(options.apiKeyId, { token, expiresAt: now + expiresIn });

  return token;
}

/**
 * Clear the JWT cache for a specific key, or all keys if none specified.
 *
 * @param apiKeyId - The API key ID to clear, or omit to clear all
 */
export function clearJwtCache(apiKeyId?: string): void {
  if (apiKeyId) {
    jwtCache.delete(apiKeyId);
  } else {
    jwtCache.clear();
  }
}

// =============================================================================
// Auth Headers Helper
// =============================================================================

/**
 * Create a `createAuthHeaders` function compatible with `FacilitatorConfig`.
 *
 * Returns a function that generates `Authorization: Bearer <jwt>` headers
 * for every facilitator endpoint (verify, settle, supported). The JWT is
 * automatically cached and refreshed.
 *
 * @param apiKeyId - PayAI API Key ID
 * @param apiKeySecret - PayAI API Key Secret (raw base64 or `payai_sk_` prefixed)
 * @returns A function matching the `FacilitatorConfig.createAuthHeaders` signature
 */
export function createPayAIAuthHeaders(
  apiKeyId: string,
  apiKeySecret: string,
): () => Promise<{
  verify: Record<string, string>;
  settle: Record<string, string>;
  supported: Record<string, string>;
}> {
  return async () => {
    const jwt = await getOrGenerateJwt({ apiKeyId, apiKeySecret });
    const authHeader = { Authorization: `Bearer ${jwt}` };

    return {
      verify: authHeader,
      settle: authHeader,
      supported: authHeader,
    };
  };
}
